mapper.select:
SELECT place_id
FROM place
WHERE place_name = #{placeName}
  AND address    = #{address}
  AND ROWNUM = 1

SELECT * FROM ( SELECT p.place_id AS placeId, p.place_name AS placeName, p.address AS address, p.latitude AS latitude, p.longitude AS longitude, p.category AS category, p.image_url AS imageUrl, p.phone_number AS phoneNumber, p.description AS description, ROWNUM AS rn FROM place p WHERE p.latitude IS NOT NULL AND p.longitude IS NOT NULL
AND (
p.address LIKE '%' || #{city} || '%'
)
AND p.category = #{category}
ORDER BY CASE WHEN p.image_url IS NOT NULL AND p.image_url != '' THEN 0 ELSE 1 END, DBMS_RANDOM.VALUE ) WHERE rn > #{offset} AND rn <= (#{offset} + #{limit})

SELECT COUNT(*) FROM place p WHERE p.latitude IS NOT NULL AND p.longitude IS NOT NULL
AND (
p.address LIKE '%' || #{city} || '%'
)
AND p.category = #{category}
